# hypercare_exit_check.py — evaluate phase exit criteria
from prometheus_api_client import PrometheusConnect
import json
from datetime import datetime, timedelta

prom = PrometheusConnect(url="http://prometheus:9090")

def check_p0_free_window(hours: int) -> bool:
    """True if no P0 incidents in the last `hours` hours."""
    result = prom.custom_query(
        f'increase(claude_p0_incidents_total[{hours}h])'
    )
    count = float(result[0]["value"][1]) if result else 0
    return count == 0

def check_support_volume_trend(days: int) -> str:
    """Return 'declining', 'stable', or 'increasing' over last N days."""
    today = prom.custom_query('claude_support_tickets_daily')[0]["value"][1]
    yesterday = prom.custom_query('claude_support_tickets_daily offset 1d')[0]["value"][1]
    delta = float(today) - float(yesterday)
    if delta < -5:
        return "declining"
    elif delta > 5:
        return "increasing"
    return "stable"

def evaluate_intensive_to_transition() -> dict:
    checks = {
        "p0_free_48h": check_p0_free_window(48),
        "support_declining": check_support_volume_trend(2) in ("declining", "stable"),
    }
    all_pass = all(checks.values())
    return {"phase": "intensive->transition", "checks": checks, "ready": all_pass}

result = evaluate_intensive_to_transition()
print(json.dumps(result, indent=2))
if result["ready"]:
    print("\nPhase exit criteria MET. Proceed to Transition phase.")
else:
    failed = [k for k, v in result["checks"].items() if not v]
    print(f"\nPhase exit criteria NOT MET. Failing checks: {failed}")
